512	        const { start_logits, end_logits } = await this.model(inputs);
513	        const input_ids = inputs.input_ids.tolist();
514	        const attention_mask = inputs.attention_mask.tolist();
515	
516	        // TODO: add support for `return_special_tokens_mask`
517	        const special_tokens = this.tokenizer.all_special_ids;
518	
519	        /** @type {QuestionAnsweringOutput[]} */
520	        const toReturn = [];
521	        for (let j = 0; j < start_logits.dims[0]; ++j) {
522	            const ids = input_ids[j];
523	            const sepIndex = ids.findIndex(x =>
524	                // We use == to match bigint with number
525	                // @ts-ignore
526	                x == this.tokenizer.sep_token_id
527	            );
528	
529	
530	            const valid_mask = attention_mask[j].map((y, ix) => (
531	                y == 1
532	                && (
533	                    ix === 0 // is cls_token
534	                    || (
535	                        ix > sepIndex
536	                        && special_tokens.findIndex(x => x == ids[ix]) === -1 // token is not a special token (special_tokens_mask == 0)
537	                    )
538	                )
539	            ));
540	
541	            const start = start_logits[j].tolist();
542	            const end = end_logits[j].tolist();
543	
544	            // Now, we mask out values that can't be in the answer
545	            // NOTE: We keep the cls_token unmasked (some models use it to indicate unanswerable questions)
546	            for (let i = 1; i < start.length; ++i) {
547	                if (
548	                    attention_mask[j] == 0 // is part of padding
549	                    || i <= sepIndex // is before the sep_token
550	                    || special_tokens.findIndex(x => x == ids[i]) !== -1 // Is a special token
551	                ) {
552	                    // Make sure non-context indexes in the tensor cannot contribute to the softmax
553	                    start[i] = -Infinity;
554	                    end[i] = -Infinity;
555	                }
556	            }
557	
558	            // Normalize logits and spans to retrieve the answer
559	            const start_scores = softmax(start).map((x, i) => [x, i]);
560	            const end_scores = softmax(end).map((x, i) => [x, i]);
561	
562	            // Mask CLS
563	            start_scores[0][0] = 0;
564	            end_scores[0][0] = 0;
565	
566	            // Generate all valid spans and select best ones
567	            const options = product(start_scores, end_scores)
568	                .filter(x => x[0][1] <= x[1][1])
569	                .map(x => [x[0][1], x[1][1], x[0][0] * x[1][0]])
570	                .sort((a, b) => b[2] - a[2]);
571	
572	            for (let k = 0; k < Math.min(options.length, top_k); ++k) {
573	                const [start, end, score] = options[k];
574	
575	                const answer_tokens = ids.slice(start, end + 1)
576	
577	                const answer = this.tokenizer.decode(answer_tokens, {
578	                    skip_special_tokens: true,
579	                });
580	
581	                // TODO add start and end?
582	                // NOTE: HF returns character index
583	                toReturn.push({
584	                    answer, score
585	                });
586	            }
587	        }
588	
589	        // Mimic HF's return type based on top_k
590	        return (top_k === 1) ? toReturn[0] : toReturn;
